inputs.customFunctionJavascriptFunction:
const inboxQuery = String($inboxQuery || '').trim();
const triageCollectionId = String($triageCollectionId || '').trim();
const missing = [];
if (!triageCollectionId) missing.push('triageCollectionId');
if (!inboxQuery) missing.push('inboxQuery');
const guidance = [
  'Configuration required before this flow can triage inbox emails.',
  missing.length ? `Missing startState keys: ${missing.join(', ')}` : '',
  '',
  'Required setup:',
  '1. Set startState.triageCollectionId to the Collections log collection ID.',
  '2. Set startState.inboxQuery to the Gmail inbox filter you want to triage.',
  '3. Connect a gmailOAuth2 credential on the Gmail node after import.',
  '4. Select a model on the AI Triage LLM node.'
].filter(Boolean).join('\n');
return {
  hasRequiredConfig: missing.length === 0,
  setupGuidance: guidance
};

const raw = $gmailMessagesRaw;
let parsed = raw;
if (typeof parsed === 'string') {
  try {
    parsed = JSON.parse(parsed);
  } catch {
    parsed = [];
  }
}
const items = Array.isArray(parsed) ? parsed : [];
const email = items[0];
if (!email) {
  return {
    hasEligibleEmail: false,
    sourceFromEmail: '',
    sourceFromName: '',
    sourceSubject: '',
    sourceBody: ''
  };
}
const fromRaw = String(email.from || '').trim();
const subject = String(email.subject || '').trim();
const body = String(email.body || '').trim();
let sourceFromEmail = fromRaw;
let sourceFromName = '';
const angleMatch = fromRaw.match(/^(.*?)<([^>]+)>$/);
if (angleMatch) {
  sourceFromName = angleMatch[1].replace(/"/g, '').trim();
  sourceFromEmail = angleMatch[2].trim();
}
return {
  hasEligibleEmail: true,
  sourceFromEmail,
  sourceFromName,
  sourceSubject: subject,
  sourceBody: body
};

const normalize = (value) => String(value || '').toLowerCase().replace(/\s+/g, ' ').trim();
const raw = `${normalize($fromEmail)}|${normalize($subject)}|${normalize($body).slice(0, 2000)}`;
let hash = 5381;
for (let i = 0; i < raw.length; i++) {
  hash = ((hash << 5) + hash) + raw.charCodeAt(i);
  hash = hash >>> 0;
}
return `fp_${hash.toString(16)}`;

const raw = $existingItems;
let items = raw;
if (typeof items === 'string') {
  try {
    items = JSON.parse(items);
  } catch {
    items = [];
  }
}
return {
  alreadyProcessed: Array.isArray(items) && items.length > 0
};

const clean = (value, fallback = '') => String(value ?? fallback).trim();
const allowedCategory = ['support', 'sales', 'finance', 'internal', 'spam'];
const allowedPriority = ['low', 'normal', 'high', 'critical'];
const allowedOwner = ['support', 'sales', 'finance', 'ops', 'leadership'];
const category = allowedCategory.includes(clean($triageCategory).toLowerCase()) ? clean($triageCategory).toLowerCase() : 'internal';
const priority = allowedPriority.includes(clean($triagePriority).toLowerCase()) ? clean($triagePriority).toLowerCase() : 'normal';
const suggestedOwner = allowedOwner.includes(clean($triageSuggestedOwner).toLowerCase()) ? clean($triageSuggestedOwner).toLowerCase() : clean($defaultOwnerTeam, 'ops');
const createdAtIso = new Date().toISOString();
const datePart = createdAtIso.slice(0, 10).replace(/-/g, '');
const shortId = Math.random().toString(36).slice(2, 8).toUpperCase();
const prefix = clean($recordPrefix, 'TRI').toUpperCase();
const recordId = `${prefix}-${datePart}-${shortId}`;
const payload = {
  recordId,
  createdAt: createdAtIso,
  status: clean($defaultStatus, 'triaged'),
  fromEmail: clean($fromEmail),
  fromName: clean($fromName),
  subject: clean($subject),
  messageBody: clean($messageBody),
  emailFingerprint: clean($emailFingerprint),
  category,
  priority,
  summary: clean($triageSummary, clean($subject)),
  reason: clean($triageReason),
  suggestedOwner
};
return {
  recordId,
  createdAtIso,
  category,
  priority,
  suggestedOwner,
  triageRecordPayload: JSON.stringify(payload)
};

